// register.component.ts - VERSIONE AGGIORNATA CON FORNITORI
import { Component, inject, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule, AbstractControl } from '@angular/forms';
import { Router, ActivatedRoute, RouterLink } from '@angular/router';
import { CommonModule } from '@angular/common';
import { AuthService } from '../../services/Base/auth.service';
import { RegisterRequest } from '../../models';
import { LucideAngularModule } from 'lucide-angular';
import { Header } from '../../shared/header/header';

@Component({
  selector: 'app-register',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink, LucideAngularModule, Header],
  templateUrl: './register.html',
  styleUrls: ['../login/login.css']
})
export class Register implements OnInit {
  private fb = inject(FormBuilder);
  private authService = inject(AuthService);
  private router = inject(Router);
  private route = inject(ActivatedRoute);

  registerForm!: FormGroup;
  isLoading = false;
  errorMessage = '';
  isRestaurant = false;
  isSupplier = false;
  showPassword = false;
  showConfirmPassword = false;


  ngOnInit() {
    // Determina il tipo di registrazione
    const role = this.route.snapshot.paramMap.get('role');
    this.isRestaurant = role === 'restaurant';
    this.isSupplier = role === 'supplier'; // NUOVO

    this.initializeForm();
  }

  private initializeForm() {
    this.registerForm = this.fb.group({
      // Campi base
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      confirmPassword: ['', [Validators.required]],
      firstName: ['', [Validators.required]],
      lastName: ['', [Validators.required]],
      phone: [''],
      policy: [false, [Validators.requiredTrue]],
      
      // Campi condizionali
      restaurantName: [this.isRestaurant ? '' : '', this.isRestaurant ? Validators.required : []],
      
      // NUOVI CAMPI FORNITORE
      companyName: [this.isSupplier ? '' : '', this.isSupplier ? Validators.required : []],
      contactName: [this.isSupplier ? '' : '', this.isSupplier ? Validators.required : []],
      supplierAddress: [this.isSupplier ? '' : ''],
      supplierDescription: [this.isSupplier ? '' : '']
    }, { validators: this.passwordMatchValidator });
  }

  get rememberMe() { return this.registerForm.get('policy'); }

  passwordMatchValidator(form: AbstractControl) {
    const password = form.get('password')?.value;
    const confirmPassword = form.get('confirmPassword')?.value;
    return password === confirmPassword ? null : { passwordMismatch: true };
  }

async onSubmit() {
  if (this.registerForm.invalid || this.isLoading) return;

  this.isLoading = true;
  this.errorMessage = '';

  const formValue = this.registerForm.value;

  try {
    // Determina il ruolo
    const userRole = this.determineUserRole();

    const registerData: RegisterRequest = {
      email: formValue.email.toLowerCase().trim(),
      password: formValue.password,
      user_data: {
        first_name: formValue.firstName,
        last_name: formValue.lastName,
        phone: formValue.phone,
        role: userRole
      },
      restaurant_data: this.isRestaurant ? {
        name: formValue.restaurantName,
        address: '',
        phone: formValue.phone || '',
        email: formValue.email,
        description: '',
        cuisine_type: '',
        allow_table_selection: false, 
        accepts_delivery: false,     
        accepts_takeaway: false       
      } : undefined,
      // NUOVO: Dati fornitore
      supplier_data: this.isSupplier ? {
        company_name: formValue.companyName,
        contact_name: formValue.contactName,
        email: formValue.email,
        phone: formValue.phone || '',
        address: formValue.supplierAddress,
        description: formValue.supplierDescription
      } : undefined
    };

    const result = await this.authService.register(registerData);

    // 🔥 CORREZIONE COMPLETA - Gestione robusta degli errori
    if (result.error) {
      // Controlla il tipo di errore in modo esplicito
      if (typeof result.error === 'string') {
        this.errorMessage = result.error;
      } else if (result.error && typeof result.error === 'object') {
        // Usa type assertion per accedere a message
        const errorObj = result.error as any;
        this.errorMessage = errorObj.message || errorObj.toString();
      } else {
        this.errorMessage = 'Errore durante la registrazione';
      }
      
      console.error('Registration error details:', result.error);
    } else if (result.user) {
      console.log('✅ Registration successful, user:', result.user.id);
      this.errorMessage = 'Registrazione completata! Reindirizzamento...';
      
      this.redirectAfterRegistration(result);
    }

  } catch (error: unknown) {
    // 🔥 CORREZIONE - Gestione type-safe degli errori
    if (error instanceof Error) {
      this.errorMessage = 'Errore durante la registrazione: ' + error.message;
    } else if (typeof error === 'string') {
      this.errorMessage = 'Errore durante la registrazione: ' + error;
    } else {
      this.errorMessage = 'Errore sconosciuto durante la registrazione';
    }
    console.error('Registration exception:', error);
  } finally {
    this.isLoading = false;
  }
}

  private determineUserRole(): 'customer' | 'restaurant_owner' | 'supplier' {
    if (this.isRestaurant) return 'restaurant_owner';
    if (this.isSupplier) return 'supplier';
    return 'customer';
  }

  private redirectAfterRegistration(result: any) {
    setTimeout(() => {
      if (this.isRestaurant && result.restaurant) {
        this.router.navigate(['/restaurant/dashboard']);
      } else if (this.isSupplier) {
        // I fornitori vengono reindirizzati all'area fornitore (anche se in attesa di approvazione)
        this.router.navigate(['/supplier/dashboard']);
      } else {
        this.router.navigate(['/customer/menu-display']);
      }
    }, 2000);
  }

  // Getters per template
  get email() { return this.registerForm.get('email'); }
  get password() { return this.registerForm.get('password'); }
  get confirmPassword() { return this.registerForm.get('confirmPassword'); }
  get firstName() { return this.registerForm.get('firstName'); }
  get lastName() { return this.registerForm.get('lastName'); }
  get restaurantName() { return this.registerForm.get('restaurantName'); }
  
  // NUOVI GETTERS FORNITORE
  get companyName() { return this.registerForm.get('companyName'); }
  get contactName() { return this.registerForm.get('contactName'); }
  get supplierAddress() { return this.registerForm.get('supplierAddress'); }
  get supplierDescription() { return this.registerForm.get('supplierDescription'); }

    togglePasswordVisibility() {
    this.showPassword = !this.showPassword;
  }

  toggleConfirmPasswordVisibility() {
    this.showConfirmPassword = !this.showConfirmPassword;
  }

}